// Generated by OrchestKit Claude Plugin
// Created: 2026-04-26 (M119 #1476)

/**
 * Per-session nudge-outcome marker.
 *
 * Written by `lifecycle/pre-compact-task-done-prompt` when it blocks a
 * compact, then consumed by:
 *
 *   - `lifecycle/post-compact-recovery` — sees marker for current session →
 *     records `outcome: "compact"` and resolves the marker.
 *   - SessionStart resolver — sees marker from a *different* session →
 *     records `outcome: "clear"` (recent) or `outcome: "ignored"` (>24h).
 *
 * Outcomes are appended to the same `pre-compact-decisions.jsonl` telemetry
 * file used by the nudge itself, so analytics can compute fire→outcome rates
 * from a single stream.
 */

import { existsSync, readFileSync, mkdirSync, appendFileSync, writeFileSync, readdirSync, unlinkSync } from 'node:fs';
import { join, dirname } from 'node:path';

export interface NudgeMarker {
  sessionId: string;
  firedAt: string;
  resolved: boolean;
}

export interface OutcomeEntry {
  timestamp: string;
  type: 'outcome';
  user_action: 'compact' | 'clear' | 'ignored';
  nudge_fired_at: string;
  nudge_session_id: string;
  age_ms: number;
}

const DIR_NAME = 'state';

function markerDir(projectDir: string): string {
  return join(projectDir, '.claude', DIR_NAME);
}

function markerPath(projectDir: string, sessionId: string): string {
  return join(markerDir(projectDir), `nudge-outcome-${sessionId}.json`);
}

export function telemetryPath(projectDir: string): string {
  return join(projectDir, '.claude', 'telemetry', 'pre-compact-decisions.jsonl');
}

export function writeMarker(projectDir: string, sessionId: string, firedAt: string): void {
  try {
    const dir = markerDir(projectDir);
    mkdirSync(dir, { recursive: true });
    const payload: NudgeMarker = { sessionId, firedAt, resolved: false };
    writeFileSync(markerPath(projectDir, sessionId), JSON.stringify(payload, null, 2));
  } catch {
    // best-effort
  }
}

export function readMarker(projectDir: string, sessionId: string): NudgeMarker | null {
  const p = markerPath(projectDir, sessionId);
  if (!existsSync(p)) return null;
  try {
    const parsed = JSON.parse(readFileSync(p, 'utf8')) as Partial<NudgeMarker>;
    if (!parsed.sessionId || !parsed.firedAt) return null;
    return {
      sessionId: parsed.sessionId,
      firedAt: parsed.firedAt,
      resolved: parsed.resolved === true,
    };
  } catch {
    return null;
  }
}

/** Remove the marker file (call after recording an outcome). */
export function deleteMarker(projectDir: string, sessionId: string): void {
  try {
    unlinkSync(markerPath(projectDir, sessionId));
  } catch {
    // already gone
  }
}

/** List markers from OTHER sessions (for SessionStart resolver). */
export function listForeignMarkers(projectDir: string, currentSessionId: string): NudgeMarker[] {
  const dir = markerDir(projectDir);
  if (!existsSync(dir)) return [];
  const out: NudgeMarker[] = [];
  try {
    for (const file of readdirSync(dir)) {
      const m = file.match(/^nudge-outcome-(.+)\.json$/);
      if (!m) continue;
      const sid = m[1];
      if (sid === currentSessionId) continue;
      const marker = readMarker(projectDir, sid);
      if (marker && !marker.resolved) out.push(marker);
    }
  } catch {
    // best-effort
  }
  return out;
}

export function appendOutcome(projectDir: string, entry: OutcomeEntry): void {
  const path = telemetryPath(projectDir);
  try {
    mkdirSync(dirname(path), { recursive: true });
    appendFileSync(path, `${JSON.stringify(entry)}\n`);
  } catch {
    // best-effort
  }
}
